const qs=(s,c=document)=>c.querySelector(s);const qsa=(s,c=document)=>[...c.querySelectorAll(s)];
window.maseTrack=window.maseTrack||(()=>{}); // Replace with a consent-aware analytics provider at launch.
const header=qs("[data-header]");const menuButton=qs(".menu-button");const mobileMenu=qs(".mobile-menu");
const updateHeader=()=>header?.classList.toggle("scrolled",scrollY>24);updateHeader();addEventListener("scroll",updateHeader,{passive:true});
menuButton?.addEventListener("click",()=>{const open=menuButton.getAttribute("aria-expanded")==="true";menuButton.setAttribute("aria-expanded",String(!open));mobileMenu.classList.toggle("open",!open);mobileMenu.setAttribute("aria-hidden",String(open));document.body.style.overflow=open?"":"hidden"});
const reduced=matchMedia("(prefers-reduced-motion: reduce)").matches;
if(!reduced&&"IntersectionObserver" in window){const observer=new IntersectionObserver((entries)=>entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add("in");observer.unobserve(e.target)}}),{threshold:.12,rootMargin:"0px 0px -4%"});qsa(".reveal").forEach(el=>observer.observe(el))}else qsa(".reveal").forEach(el=>el.classList.add("in"));
qsa("[data-filter]").forEach(button=>button.addEventListener("click",()=>{qsa("[data-filter]").forEach(b=>b.classList.remove("active"));button.classList.add("active");const filter=button.dataset.filter;qsa("[data-category]").forEach(card=>{card.hidden=filter!=="all"&&card.dataset.category!==filter})}));
const form=qs(".project-form");form?.addEventListener("submit",async event=>{event.preventDefault();const fields=qsa("[required]",form);let valid=true;fields.forEach(field=>{const bad=!field.value.trim()||(field.type==="email"&&!/^\S+@\S+\.\S+$/.test(field.value));field.classList.toggle("invalid",bad);if(bad)valid=false});const status=qs(".form-status",form);if(!valid){status.textContent="Please complete the highlighted fields.";return}if(form.company_website.value)return;const data=new FormData(form);const brief=["New Mase the Creative enquiry","",...Array.from(data.entries()).filter(([k])=>k!=="company_website").map(([k,v])=>`${k.replaceAll("_"," ")}: ${v}`)].join("\n");window.maseTrack("enquiry_prepared",{project:data.get("project")});try{await navigator.clipboard.writeText(brief);status.innerHTML=`Your enquiry is copied. <a href="https://instagram.com/masethecreative">Open Instagram to send it ↗</a>`}catch{status.innerHTML=`Your enquiry is ready. Copy your answers, then <a href="https://instagram.com/masethecreative">send them on Instagram ↗</a>`}});
const dot=qs(".cursor-dot");if(dot&&!reduced&&matchMedia("(pointer:fine)").matches){addEventListener("pointermove",e=>{dot.style.transform=`translate(${e.clientX}px,${e.clientY}px) translate(-50%,-50%)`;dot.classList.add("show")});qsa("a,button,input,select,textarea").forEach(el=>{el.addEventListener("pointerenter",()=>dot.classList.add("hover"));el.addEventListener("pointerleave",()=>dot.classList.remove("hover"))})}
